{"Steps":[],"Env":null,"RemainingFields":{"jobs":{"label":{"runs-on":"ubuntu-22.04","permissions":{"contents":"read","pull-requests":"write"},"steps":[{"uses":"actions/labeler@ba790c862c380240c6d5e7427be5ace9a05c754b","with":{"repo-token":"${{ secrets.GITHUB_TOKEN }}"}},{"uses":"actions/github-script@98814c53be79b1d30f795b907e553d8679345975","id":"set-result","with":{"script":"const config = {
  docs: /^docs/,
  bug: /^bug/,
  fix: /^fix/,
  chore: /^chore/,
  feat: /^feat/,
  build: /^build/,
  ci: /^ci/,
  refactor: /^refactor/,
  "breaking-change": /!:/,
};

const labels = Object.entries(config).reduce(
  (acc, cur) => (context.payload.pull_request.title.match(cur[1]) 
    ? [...acc, cur[0]] : acc),
  []
);

if (labels.length > 0) {
  await github.rest.issues.addLabels({
    owner: context.repo.owner,
    repo: context.repo.repo,
    issue_number: context.payload.pull_request.number,
    labels: labels
  });
}
","result-encoding":"string"}}]}},"name":"Labeler","on":["pull_request"]}}
